patch:
diff --git a/llvm/lib/Transforms/Utils/Local.cpp b/llvm/lib/Transforms/Utils/Local.cpp
index babd7f6b3a05..a7c630775879 100644
--- a/llvm/lib/Transforms/Utils/Local.cpp
+++ b/llvm/lib/Transforms/Utils/Local.cpp
@@ -484,6 +484,8 @@ bool llvm::wouldInstructionBeTriviallyDead(const Instruction *I,
       auto *Arg = II->getArgOperand(1);
       // If the only uses of the alloca are lifetime intrinsics, then the
       // intrinsics are dead.
+      if (!Arg->hasUseList())
+        return false;
       return llvm::all_of(Arg->uses(), [](Use &Use) {
         return isa<LifetimeIntrinsic>(Use.getUser());
       });

